(function(){"use strict";let r=[],l=[],t=[];self.onmessage=({data:o})=>{if(o.type==="clear"){r=[],l=[],t=[];return}if(o.type==="build"){t=o.nodes.map(e=>e.id),r=t.map(e=>{try{return new URL(e).pathname.toLowerCase()}catch{return e.toLowerCase()}}),l=o.nodes.map(e=>(e.title||"").toLowerCase());const n={type:"ready",nodeCount:t.length};self.postMessage(n)}if(o.type==="search"){const n=o.query.toLowerCase();if(!n){const s={type:"results",matchIds:[]};self.postMessage(s);return}const e=[];for(let s=0;s<t.length&&e.length<200;s++)(r[s].includes(n)||t[s].toLowerCase().includes(n)||l[s].includes(n))&&e.push(t[s]);const p={type:"results",matchIds:e};self.postMessage(p)}}})();
